import React, { useState, useEffect } from 'react';
import './App.css';
import Sidebar from './components/Sidebar';
import Navbar from './components/Navbar';
import Dashboard from './components/Dashboard';
import WorkoutLogger from './components/WorkoutLogger';
import ExerciseLibrary from './components/ExerciseLibrary';
import Schedule from './components/Schedule';
import Profile from './components/Profile';
import Login from './pages/Login';
import Register from './pages/Register';
import { authAPI, workoutsAPI, usersAPI } from './services/api';

function App() {
  const [currentPage, setCurrentPage] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  
  const [user, setUser] = useState(null);
  const [workouts, setWorkouts] = useState([]);
  const [stats, setStats] = useState(null);

  // Check for existing login on load
  useEffect(() => {
    checkAuth();
  }, []);

  const checkAuth = async () => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        const response = await authAPI.getMe();
        setUser(response.data.user);
        setIsAuthenticated(true);
        fetchWorkouts();
        fetchStats();
      } catch (error) {
        console.log('Auth failed, clearing token');
        localStorage.removeItem('token');
      }
    }
    setLoading(false);
  };

  const fetchWorkouts = async () => {
    try {
      const response = await workoutsAPI.getWorkouts();
      setWorkouts(response.data.workouts);
    } catch (error) {
      console.log('Error fetching workouts');
    }
  };

  const fetchStats = async () => {
    try {
      const response = await workoutsAPI.getStats();
      setStats(response.data.stats);
    } catch (error) {
      console.log('Error fetching stats');
    }
  };

  const handleLogin = async (email, password) => {
    try {
      const response = await authAPI.login({ email, password });
      localStorage.setItem('token', response.data.token);
      setUser(response.data.user);
      setIsAuthenticated(true);
      fetchWorkouts();
      fetchStats();
      return { success: true };
    } catch (error) {
      return { success: false, message: error.response?.data?.message || 'Login failed' };
    }
  };

  const handleRegister = async (username, email, password) => {
    try {
      const response = await authAPI.register({ username, email, password });
      localStorage.setItem('token', response.data.token);
      setUser(response.data.user);
      setIsAuthenticated(true);
      return { success: true };
    } catch (error) {
      return { success: false, message: error.response?.data?.message || 'Registration failed' };
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    setUser(null);
    setIsAuthenticated(false);
    setWorkouts([]);
    setStats(null);
  };

  const handleWorkoutCreated = () => {
    fetchWorkouts();
    fetchStats();
  };

  const handleProfileUpdate = (updatedUser) => {
    setUser(updatedUser);
  };

  if (loading) {
    return (
      <div className="app loading-screen">
        <div className="loader">Loading...</div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return (
      <div className="auth-wrapper">
        <Register onRegister={handleRegister} onLogin={handleLogin} />
      </div>
    );
  }

  const renderPage = () => {
    switch (currentPage) {
      case 'dashboard':
        return <Dashboard user={user} stats={stats} workouts={workouts} />;
      case 'workout':
        return <WorkoutLogger user={user} onWorkoutCreated={handleWorkoutCreated} />;
      case 'library':
        return <ExerciseLibrary />;
      case 'schedule':
        return <Schedule />;
      case 'profile':
        return <Profile user={user} setUser={handleProfileUpdate} />;
      default:
        return <Dashboard user={user} stats={stats} workouts={workouts} />;
    }
  };

  return (
    <div className="app">
      <Sidebar currentPage={currentPage} setCurrentPage={setCurrentPage} onLogout={handleLogout} />
      <div className="main-wrapper">
        <Navbar user={user} onLogout={handleLogout} />
        <div className="main-content">
          {renderPage()}
        </div>
      </div>
    </div>
  );
}

export default App;
